template_data:
{% set report_title = "Treatment Summary" %}
{% set logo_img = "https://raw.githubusercontent.com/ohcnetwork/care/develop/care/static/images/logos/logo-light.svg" %}
<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8" />
    <title>{{ report_title }}</title>
    <style>
        @page {
            size: A4;
            margin: 140px 36px 60px 36px;
            @bottom-center {
                content: "Page " counter(page) " of " counter(pages);
                font-family: "Helvetica Neue", Arial, sans-serif;
                font-size: 9px;
                color: #6b7280;
            }
        }

        * { box-sizing: border-box; }

        body {
            font-family: "Helvetica Neue", Arial, sans-serif;
            color: #1f2937;
            font-size: 11px;
            line-height: 1.45;
            margin: 0;
            padding: 0;
        }

        h1, h2, h3 { color: #0d9488; margin: 0; }

        /* ---- Fixed header (repeats on every page) ---- */
        .page-header {
            position: fixed;
            top: -120px;
            left: 0;
            right: 0;
            height: 100px;
            padding: 12px 0;
            border-bottom: 2px solid #0d9488;
            display: table;
            width: 100%;
            background: #ffffff;
        }
        .page-header .header-left,
        .page-header .header-right {
            display: table-cell;
            vertical-align: middle;
        }
        .page-header .header-left { width: 70%; }
        .page-header .header-right { width: 30%; text-align: right; }
        .facility-name {
            font-size: 18px;
            font-weight: 700;
            color: #0d9488;
            margin-bottom: 2px;
        }
        .facility-meta {
            font-size: 9px;
            color: #4b5563;
            line-height: 1.3;
        }
        .header-logo {
            height: 60px;
            width: auto;
        }

        /* ---- Report title bar ---- */
        .report-title-bar {
            background: #f0fdfa;
            border-left: 4px solid #0d9488;
            padding: 8px 12px;
            margin-bottom: 14px;
        }
        .report-title-bar h2 {
            font-size: 16px;
            color: #0d9488;
        }
        .report-title-bar .meta {
            font-size: 9px;
            color: #6b7280;
            margin-top: 2px;
        }

        /* ---- Patient info grid ---- */
        .patient-grid {
            width: 100%;
            border-collapse: collapse;
            margin-bottom: 18px;
        }
        .patient-grid th,
        .patient-grid td {
            padding: 6px 10px;
            font-size: 11px;
            border: 1px solid #e5e7eb;
        }
        .patient-grid th {
            background: #f9fafb;
            color: #374151;
            font-weight: 600;
            text-align: left;
            width: 18%;
        }

        /* ---- Section ---- */
        .section { margin-bottom: 16px; page-break-inside: avoid; }
        .section-title {
            font-size: 12px;
            font-weight: 700;
            color: #0f172a;
            padding: 6px 10px;
            background: #f1f5f9;
            border-left: 3px solid #0d9488;
            margin-bottom: 6px;
        }

        /* ---- Data tables ---- */
        .data-table {
            width: 100%;
            border-collapse: collapse;
        }
        .data-table th,
        .data-table td {
            padding: 6px 8px;
            font-size: 10px;
            border-bottom: 1px solid #e5e7eb;
            text-align: left;
            vertical-align: top;
        }
        .data-table th {
            background: #f9fafb;
            color: #374151;
            font-weight: 600;
            border-bottom: 2px solid #e5e7eb;
        }
        .data-table tr:last-child td { border-bottom: none; }

        /* ---- Diagnostic report ---- */
        .dx-block { margin-bottom: 10px; }
        .dx-title {
            font-weight: 600;
            color: #0d9488;
            font-size: 11px;
            padding: 4px 0;
        }
        .dx-row td.indent { padding-left: 22px; color: #374151; }
        .dx-note,
        .dx-conclusion {
            font-size: 10px;
            padding: 6px 10px;
            margin-top: 4px;
            background: #f9fafb;
            border-left: 3px solid #cbd5e1;
        }

        /* ---- Footer notes ---- */
        .disclaimer {
            margin-top: 24px;
            padding-top: 10px;
            border-top: 1px dashed #cbd5e1;
            font-size: 9px;
            color: #6b7280;
            font-style: italic;
        }
        .generated {
            margin-top: 6px;
            font-size: 8px;
            color: #9ca3af;
            text-align: center;
        }

        .empty { color: #9ca3af; font-style: italic; }
    </style>
</head>

<body>
    <div class="page-header">
        <div class="header-left">
            <div class="facility-name">{{ encounter.facility.name }}</div>
            <div class="facility-meta">
                {% if encounter.facility.address %}{{ encounter.facility.address }}<br>{% endif %}
                {% if encounter.facility.phone_number %}Tel: {{ encounter.facility.phone_number | phone }}{% endif %}
            </div>
        </div>
        <div class="header-right">
            <img class="header-logo" alt="CARE" src="{{ logo_img }}">
        </div>
    </div>

    <div class="report-title-bar">
        <h2>{{ report_title }}</h2>
        <div class="meta">Generated on {{ current_datetime() }}</div>
    </div>

    {% set official_identifiers = encounter.patient.instance_identifiers
        | selectattr('config.use', 'equalto', 'Official') | list %}

    <table class="patient-grid">
        <tr>
            <th>Name</th>
            <td>{{ encounter.patient.name }}</td>
            <th>Age / Gender</th>
            <td>{{ encounter.patient.age }} &middot; {{ encounter.patient.gender | capitalize }}</td>
        </tr>
        <tr>
            <th>Phone</th>
            <td>{{ encounter.patient.phone_number | phone }}</td>
            {% if official_identifiers %}
            <th>{{ official_identifiers[0].config.display }}</th>
            <td>{{ official_identifiers[0].value }}</td>
            {% else %}
            <th>Blood Group</th>
            <td>{{ encounter.patient.blood_group or '-' }}</td>
            {% endif %}
        </tr>
        <tr>
            <th>Address</th>
            <td colspan="3">{{ encounter.patient.address or '-' }}</td>
        </tr>
        <tr>
            <th>Admission</th>
            <td>{{ encounter.start_time | datetime }}</td>
            <th>Discharge</th>
            <td>{{ (encounter.end_time | datetime) if encounter.end_time else '-' }}</td>
        </tr>
    </table>

    {% set allergies = encounter.allergy_intolerances.filter(
        exclude_clinical_status="inactive",
        exclude_verification_status="entered_in_error") | list %}
    {% if allergies %}
    <div class="section">
        <div class="section-title">Allergies</div>
        <table class="data-table">
            <thead>
                <tr>
                    <th style="width:30%">Allergy</th>
                    <th style="width:15%">Status</th>
                    <th style="width:15%">Criticality</th>
                    <th style="width:15%">Verification</th>
                    <th>Note</th>
                </tr>
            </thead>
            <tbody>
                {% for allergy in allergies %}
                <tr>
                    <td>{{ allergy.name }}</td>
                    <td>{{ allergy.clinical_status | capitalize }}</td>
                    <td>{{ allergy.criticality | capitalize }}</td>
                    <td>{{ allergy.verification_status | capitalize }}</td>
                    <td>{{ allergy.note or '-' }}</td>
                </tr>
                {% endfor %}
            </tbody>
        </table>
    </div>
    {% endif %}

    {% set symptoms = encounter.symptoms.filter(
        exclude_clinical_status="inactive",
        exclude_verification_status="entered_in_error") | list %}
    {% if symptoms %}
    <div class="section">
        <div class="section-title">Symptoms</div>
        <table class="data-table">
            <thead>
                <tr>
                    <th style="width:35%">Symptom</th>
                    <th style="width:15%">Status</th>
                    <th style="width:15%">Verification</th>
                    <th style="width:15%">Onset</th>
                    <th>Note</th>
                </tr>
            </thead>
            <tbody>
                {% for symptom in symptoms %}
                <tr>
                    <td>{{ symptom.name }}</td>
                    <td>{{ symptom.clinical_status | capitalize }}</td>
                    <td>{{ symptom.verification_status | capitalize }}</td>
                    <td>{{ (symptom.onset | date) if symptom.onset else '-' }}</td>
                    <td>{{ symptom.note or '-' }}</td>
                </tr>
                {% endfor %}
            </tbody>
        </table>
    </div>
    {% endif %}

    {% set diagnoses = encounter.diagnoses.filter(
        exclude_clinical_status="inactive",
        exclude_verification_status="entered_in_error") | list %}
    {% if diagnoses %}
    <div class="section">
        <div class="section-title">Diagnoses</div>
        <table class="data-table">
            <thead>
                <tr>
                    <th style="width:35%">Diagnosis</th>
                    <th style="width:15%">Status</th>
                    <th style="width:15%">Verification</th>
                    <th style="width:15%">Onset</th>
                    <th>Note</th>
                </tr>
            </thead>
            <tbody>
                {% for diagnosis in diagnoses %}
                <tr>
                    <td>{{ diagnosis.name }}</td>
                    <td>{{ diagnosis.clinical_status | capitalize }}</td>
                    <td>{{ diagnosis.verification_status | capitalize }}</td>
                    <td>{{ (diagnosis.onset | date) if diagnosis.onset else '-' }}</td>
                    <td>{{ diagnosis.note or '-' }}</td>
                </tr>
                {% endfor %}
            </tbody>
        </table>
    </div>
    {% endif %}

    {% set prescriptions = encounter.medication_prescriptions | list %}
    {% if prescriptions %}
    <div class="section">
        <div class="section-title">Medications</div>
        <table class="data-table">
            <thead>
                <tr>
                    <th style="width:40%">Medicine</th>
                    <th style="width:20%">Dosage</th>
                    <th style="width:20%">Frequency</th>
                    <th>Duration</th>
                </tr>
            </thead>
            <tbody>
            {% for mp in prescriptions %}
                {% for medication in mp.medications.filter(status="active") %}
                    {% if medication.dosage_instructions %}
                        {% for di in medication.dosage_instructions %}
                        <tr>
                            <td>{{ medication.name }}</td>
                            <td>{{ di.dosage or '-' }}</td>
                            <td>{{ di.frequency or '-' }}</td>
                            <td>{{ di.duration or '-' }}</td>
                        </tr>
                        {% endfor %}
                    {% else %}
                        <tr>
                            <td>{{ medication.name }}</td>
                            <td colspan="3" class="empty">No dosage instructions</td>
                        </tr>
                    {% endif %}
                {% endfor %}
            {% endfor %}
            </tbody>
        </table>
    </div>
    {% endif %}

    {% set reports = encounter.diagnostic_reports.filter(status="final") | list %}
    {% if reports %}
    <div class="section">
        <div class="section-title">Diagnostic Reports</div>
        {% for diagnostic_report in reports %}
        <div class="dx-block">
            {% if diagnostic_report.service_request and diagnostic_report.service_request.title %}
            <div class="dx-title">{{ diagnostic_report.service_request.title }}</div>
            {% endif %}
            <table class="data-table">
                <thead>
                    <tr>
                        <th style="width:18%">Date</th>
                        <th style="width:32%">Test</th>
                        <th style="width:18%">Result</th>
                        <th style="width:17%">Range</th>
                        <th>Interpretation</th>
                    </tr>
                </thead>
                <tbody>
                {% for observation in diagnostic_report.observations %}
                    <tr class="dx-row">
                        <td>{{ observation.effective_datetime | date }}</td>
                        <td>{{ observation.title }}</td>
                        <td>
                            {% if observation.value and observation.value.value %}
                                {{ observation.value.value }}{% if observation.value.unit %} {{ observation.value.unit }}{% endif %}
                            {% else %}-{% endif %}
                        </td>
                        <td>
                            {% set matched = (observation.reference_range or [])
                                | selectattr("interpretation", "equalto", observation.interpretation) | list %}
                            {% if matched %}
                                {% set range = matched[0] %}
                                {% set min_val = range.min | default(0) | float %}
                                {% set max_val = range.max | default(0) | float %}
                                {% if min_val > 0 and max_val > 0 %}{{ min_val }} - {{ max_val }}
                                {% elif max_val > 0 %}&lt; {{ max_val }}
                                {% elif min_val > 0 %}&gt; {{ min_val }}
                                {% else %}-{% endif %}
                            {% else %}-{% endif %}
                        </td>
                        <td>{{ (observation.interpretation | capitalize) if observation.interpretation else '-' }}</td>
                    </tr>
                    {% for component in (observation.component or []) %}
                    <tr class="dx-row">
                        <td></td>
                        <td class="indent">&mdash; {{ component.title }}</td>
                        <td>
                            {% if component.value and component.value.value %}
                                {{ component.value.value }}{% if component.value.unit %} {{ component.value.unit }}{% endif %}
                            {% else %}-{% endif %}
                        </td>
                        <td>-</td>
                        <td>{{ (component.interpretation | capitalize) if component.interpretation else '-' }}</td>
                    </tr>
                    {% endfor %}
                {% endfor %}
                </tbody>
            </table>
            {% if diagnostic_report.note %}
            <div class="dx-note"><strong>Note:</strong> {{ diagnostic_report.note }}</div>
            {% endif %}
            {% if diagnostic_report.conclusion %}
            <div class="dx-conclusion"><strong>Conclusion:</strong> {{ diagnostic_report.conclusion }}</div>
            {% endif %}
        </div>
        {% endfor %}
    </div>
    {% endif %}

    {% if encounter.discharge_summary_advice %}
    <div class="section">
        <div class="section-title">Discharge Advice</div>
        <div style="padding: 8px 10px; font-size: 11px; white-space: pre-line;">
            {{ encounter.discharge_summary_advice }}
        </div>
    </div>
    {% endif %}

    <div class="disclaimer">
        Note: Content of this {{ report_title }} will not be changed once the patient is discharged from the
        hospital. Please bring this report when you come for checkup. This {{ report_title }} is not a legal
        document or certificate.
    </div>
    <div class="generated">
        This is a computer-generated {{ report_title }}.
    </div>
</body>
</html>
